#!/usr/bin/env python3
"""
MKT Original — 2 Kings chapters 9–11 (fill: verse-sparse chapters)
Run: python3 scripts/zc-original-2kings-fill-9-11.py

Covers all missing verses:
  ch 9: v22 exists; fills v1–21, v23–37  (36 verses)
  ch10: v16 exists; fills v1–15, v17–36  (35 verses)
  ch11: v14 exists; fills v1–13, v15–21  (20 verses)

MKT = Meaning-Knowledge-Translation: what the Hebrew says and means.
"""

import json
from pathlib import Path

ROOT = Path(__file__).resolve().parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

TWO_KINGS_ORIGINAL = {
    "9": {
        "1": "<p><b>v1 — The young prophet sent to Ramoth-Gilead</b><br>Elisha summons one of the <i>benei ha-neviim</i> (sons of the prophets — the prophetic guild) and gives him a flask of oil and a commission. The word is <i>shemen</i> (oil), the element of royal and priestly consecration. The destination is Ramoth-Gilead, the frontier garrison where Israel and Aram have been contesting control (cf. 1 Kings 22; 2 Kings 8:28). Elisha does not go himself — the anonymous young prophet acts as deputy, and the haste of the commission ('<i>hakhen motneicha</i>' — gird your loins) signals the urgency of what follows.</p>",
        "2": "<p><b>v2 — Find Jehu son of Jehoshaphat</b><br>The target is identified precisely: <i>Yehu ben Yehoshafat ben Nimshi</i>. The double patronymic (son of Jehoshaphat son of Nimshi) is unusual and likely signals that Jehu was already known to the narrative audience as the great soldier. He is to be separated from his companions and brought to an inner chamber (<i>cheder be-cheder</i> — lit. room within room), a phrase suggesting secrecy. The anointing is politically explosive and must be prepared covertly before announcement.</p>",
        "3": "<p><b>v3 — Pour the oil and flee</b><br>The young prophet is told: pour the oil on his head, declare 'Thus says the LORD: I anoint you king over Israel,' then open the door and flee without delay (<i>ve-nas'ta ve-lo techakeh</i> — flee and do not wait). This compressed instruction highlights the dangerous nature of the commission — it is a revolutionary act performed in an occupied military zone while the sitting king (Joram) is recovering from battle wounds in Jezreel. The prophet's flight after anointing underscores that this is a word dropped like a spark into dry tinder.</p>",
        "4": "<p><b>v4 — The young man goes to Ramoth-Gilead</b><br>The narrative is spare: the young prophet (literally 'the young man, the servant of the prophet') goes to Ramoth-Gilead and finds the army commanders sitting together. No dialogue is recorded; the text focuses on the act of obedience. The military setting — commanders seated, presumably in a war council — frames what follows as an act performed in the heart of Israel's military establishment.</p>",
        "5": "<p><b>v5 — A word for you, commander</b><br>The prophet announces he has a word (<i>davar</i>) for Jehu specifically. Jehu asks 'For which of us?' (<i>el-mi</i>), and the prophet says 'For you, commander.' The form <i>hassar</i> (the commander/officer) frames Jehu's current status — he is still a military officer, not yet king. The transition from <i>hassar</i> to <i>melech</i> (king) is precisely what the next verses accomplish.</p>",
        "6": "<p><b>v6 — The anointing oracle in the inner room</b><br>Brought inside, Jehu receives the oil poured on his head and the declaration: <i>'Koh amar YHWH Elohei Yisrael: meshachtika le-melech al-am YHWH al-Yisrael'</i> — 'Thus says the LORD God of Israel: I anoint you king over the people of the LORD, over Israel.' The phrase <i>am YHWH</i> (people of the LORD) is significant — it frames the kingship as stewardship of a covenant people, not merely political authority. The anointing by oil makes this a sacred, not merely military, appointment.</p>",
        "7": "<p><b>v7 — Strike down the house of Ahab</b><br>The mission is stated: destroy (<i>hikita</i>) the house of Ahab your master, so that I may avenge the blood of my servants the prophets and the blood of all the servants of the LORD from the hand of Jezebel. The term <i>avenge</i> is <i>niqamti</i> (I will avenge — 1st person divine), framing the purge as God's own justice administered through Jehu. <i>Jezebel</i> is named specifically as the one from whose hand God will exact blood-guilt — her role in the Baal persecution and prophetic deaths is the central charge.</p>",
        "8": "<p><b>v8 — The whole house of Ahab shall perish</b><br>The oracle extends to every male in Ahab's house: <i>kol-beit Achav</i> will be cut off, both the confined and the free (<i>atzur ve-azuv</i> — a formulaic phrase for totality, covering all social categories). The same formula was used for the judgments against Jeroboam (1 Kings 14:10) and Baasha (1 Kings 16:11). Ahab's dynasty joins the pattern of dynastic elimination for apostasy that structures Kings throughout.</p>",
        "9": "<p><b>v9 — Like the house of Jeroboam and the house of Baasha</b><br>The oracle makes the comparison explicit: the house of Ahab will be made like the house of Jeroboam son of Nebat and like the house of Baasha son of Ahijah. These two prior dynasties were each annihilated for leading Israel into sin. The pattern is now completing its third instance with Ahab's line. The Deuteronomic theology of Kings traces a consistent logic: dynasties that corrupt the covenant are cut off, often through violence commissioned by prophetic word.</p>",
        "10": "<p><b>v10 — Dogs shall eat Jezebel</b><br>The oracle closes with the fate of Jezebel: <i>'ve-et Izevel yokhlu ha-kelavim be-chelkat Yizreel ve-ein qover'</i> — 'The dogs shall eat Jezebel in the plot of Jezreel, and there shall be none to bury her.' No burial is the ultimate disgrace in the ancient world — to be eaten by dogs is to be denied all dignity in death. This directly fulfills Elijah's word in 1 Kings 21:23. The young prophet then opens the door and flees, as instructed.</p>",
        "11": "<p><b>v11 — Is all well? Why did this madman come to you?</b><br>When Jehu returns to the other commanders, they ask about the encounter: <i>ha-shalom</i> (is it well / is there peace?) — the same word that will echo grimly in v17-19. They call the young prophet <i>ha-meshugga</i> (the madman/the mad one) — a term used for ecstatic prophets viewed with suspicion by the military establishment (cf. Jer 29:26). The pejorative reveals the uneasy relationship between prophetic enthusiasm and military culture in Israel.</p>",
        "12": "<p><b>v12 — Jehu reveals the anointing</b><br>When pressed, Jehu reveals the substance of what was said: <i>koh ve-khoh diber elai</i> — 'He spoke to me thus and thus.' He then recites the anointing oracle. The moment of disclosure is charged — these are the men who will either support or resist the revolution. Their response (v13) shows they immediately embrace it.</p>",
        "13": "<p><b>v13 — Garments spread on the steps: instant acclamation</b><br>The commanders each took his garment and placed it beneath Jehu on the bare steps (<i>ha-garem</i>), blew the shofar (<i>tiqe'u ba-shofar</i>), and proclaimed <i>'Yehu melech'</i> — 'Jehu is king.' The garment-spreading is a spontaneous royal gesture (cf. Matt 21:8 — palms and cloaks for Jesus), here performed on a staircase rather than a throne room. The shofar proclamation in a military garrison marks this as a coup born of prophetic word and military consent simultaneously.</p>",
        "14": "<p><b>v14 — Jehu conspires against Joram</b><br>The narrative provides a brief historical parenthesis: Joram (the king of Israel) had been at Ramoth-Gilead guarding against Aram with all Israel, because of Hazael king of Aram. Joram had gone to Jezreel to recover from wounds received in battle. The conspiratorial context (<i>va-yiqshor Yehu ben Yehoshafat ben Nimshi el-Yoram</i>) positions Jehu as a military officer turning on his own sovereign — authorized only by the prophetic commission just received.</p>",
        "15": "<p><b>v15 — Seal Ramoth-Gilead; let no one escape to tell Jezreel</b><br>Jehu's first strategic move is information control: <i>im yesh nafshechem al-yetze palit min-ha-ir lalekhet le-haggid be-Yizreel</i> — 'If it is your wish, let no one slip out of the city to go and tell in Jezreel.' He then rides for Jezreel himself. The race against information is the drama of vv15-20 — whoever gets word to Joram first determines whether the coup succeeds or fails. Jehu's military experience shapes his tactical instincts.</p>",
        "16": "<p><b>v16 — Jehu rides to Jezreel</b><br><i>Va-yirkav Yehu va-yelekh el-Yizreel</i> — 'Jehu rode and went to Jezreel.' The forward motion begins. Joram king of Israel and Ahaziah king of Judah (who had come down to visit the convalescing Joram) are both in Jezreel — a detail that makes Jehu's arrival the convergence point for two royal fates. The narrative's pace accelerates.</p>",
        "17": "<p><b>v17 — The watchman on the tower of Jezreel</b><br>The watchman (<i>ha-tzofeh</i>) on the tower sees the company of Jehu approaching and reports to Joram: 'I see a company.' Joram sends a horseman with the message <i>ha-shalom</i> — 'Is it peace?' This word <i>shalom</i> now becomes the hinge of the entire episode: asked three times (vv17, 18, 19, 22) with increasing irony, it exposes the impossibility of peace under Jezebel's house.</p>",
        "18": "<p><b>v18 — The first messenger joins Jehu's company</b><br>The messenger reaches Jehu and delivers the king's question: <i>koh amar ha-melech ha-shalom</i> — 'Thus says the king: Is it peace?' Jehu dismisses him: <i>'Ma lecha ve-la-shalom suv el-achorai'</i> — 'What do you have to do with peace? Turn behind me.' The messenger falls in behind Jehu, effectively captured by the coup without realizing it. The watchman reports to Joram that the messenger has reached the company but is not returning.</p>",
        "19": "<p><b>v19 — The second messenger also joins Jehu</b><br>A second horseman is sent with the same question (<i>ha-shalom</i>), and Jehu gives the same dismissal: 'What do you have to do with peace? Turn behind me.' He too joins the company. The repeated pattern (two messengers sent, two absorbed) creates dramatic escalation and underscores that Joram's court cannot even receive news of what is happening — the coup is swallowing its own communications.</p>",
        "20": "<p><b>v20 — The driving is like the driving of Jehu son of Nimshi</b><br>The watchman reports the approach: <i>'ha-nehigah ke-nihag Yehu ven Nimshi ki be-shigga'on yinhag'</i> — 'The driving is like the driving of Jehu son of Nimshi — for he drives furiously.' The word <i>shigga'on</i> (madness/fury) echoes the earlier 'madman' label applied to the prophet — Jehu himself is characterized by dangerous intensity. This line became proverbial (the English phrase 'driving like Jehu' derives from it), capturing a reckless, unstoppable momentum.</p>",
        "21": "<p><b>v21 — Joram goes out to meet Jehu</b><br>Joram commands his chariot harnessed and goes out with Ahaziah king of Judah to meet Jehu. They meet at the plot (<i>chelkat</i>) of Naboth the Jezreelite — the precise location is not accidental. The narrator has positioned the confrontation at the very piece of land Ahab and Jezebel seized by having Naboth murdered (1 Kings 21). Geography becomes theology: the reckoning arrives at the site of the original crime.</p>",
        "22": "<p><b>v22 — What peace can there be, while the whoredoms of Jezebel and her witchcrafts remain?</b><br><i>'Ha-shalom' asked Joram. Jehu answered: 'What peace, so long as the whoredoms (<i>zenunei</i>) of your mother Jezebel and her many witchcrafts (<i>keshafeiha</i>) are great?'</i> The word <i>zenut</i> (whoredom/harlotry) in prophetic usage means religious apostasy — turning to other gods is adultery against YHWH. <i>Keshafim</i> (sorceries/witchcrafts) covers the occult-religious apparatus of Baal worship. Jehu's answer is that there can be no shalom under a regime defined by these corruptions. The question 'is it peace?' has an impossible answer as long as Jezebel's program stands.</p>",
        "23": "<p><b>v23 — Joram turns and flees: treachery, Ahaziah!</b><br>Joram recognizes what is happening — <i>mirma</i> (treachery/deceit) — and turns his chariot to flee, shouting to Ahaziah: 'Treachery, Ahaziah!' The cry is a warning but also a recognition of betrayal from within Israel's own military. The word <i>mirma</i> (from <i>ramah</i> — to deceive) frames Jehu's coup in Joram's terms as treachery, though the narrative frames it as divine commission.</p>",
        "24": "<p><b>v24 — Jehu draws his bow and shoots Joram between the shoulders</b><br><i>Ve-Yehu male yado be-qeshet va-yak et-Yoram bein zero'otav</i> — 'Jehu filled his hand with the bow and struck Joram between the arms [shoulders/scapulae].' The arrow goes through his heart (<i>vayetze ha-chetz mi-libbo</i> — the arrow went out through his heart). Joram sinks in his chariot. The execution is swift and precise — Jehu the military man kills with a soldier's accuracy.</p>",
        "25": "<p><b>v25 — Throw him in the plot of Naboth</b><br>Jehu commands Bidkar his officer: 'Take him up and throw him in the plot (<i>chelkat</i>) of Naboth the Jezreelite.' Then he recites the word the LORD spoke against Ahab in the field of Naboth (1 Kings 21:19): 'Yesterday I saw the blood of Naboth and the blood of his sons.' The disposal site is chosen deliberately to complete a long-deferred justice. The narrator wants the reader to feel the precision: the same field, the same logic, 'paid back on this plot.'</p>",
        "26": "<p><b>v26 — The blood of Naboth and his sons</b><br>The divine word recalled here goes beyond the MT of 1 Kings 21: Jehu references 'the blood of his sons' (<i>dam banaiv</i>) — sons not mentioned in the preserved Elijah oracle. This may reflect a fuller tradition about what happened to Naboth's family (killed along with him to ensure the land transfer was legally clean), or a variant tradition. Either way, the oracle's fulfillment encompasses an entire family's blood that has gone unanswered for years.</p>",
        "27": "<p><b>v27 — Ahaziah king of Judah flees and is struck at the ascent of Gur</b><br>When Ahaziah king of Judah sees what is happening, he flees by way of the garden house (<i>beit ha-gan</i>). Jehu pursues and commands 'Strike him too' (<i>oto gam-atkuhu</i>). The blow falls at the ascent of Gur, near Ibleam. Ahaziah flees to Megiddo and dies there. His officials carry him to Jerusalem for burial — he receives a royal burial (unlike Joram and later Jezebel), presumably because he is a king of Judah and descended from David.</p>",
        "28": "<p><b>v28 — Ahaziah buried in Jerusalem in the city of David</b><br>Ahaziah's body is transported from Megiddo to Jerusalem and buried in the tomb of his ancestors in the city of David. The Chronicler's parallel (2 Chr 22:9) differs in detail about where he died, but both traditions agree on the Jerusalem burial. Ahaziah's reign — briefly described in 2 Kings 8 — lasted only one year; his end here is entangled with the purge of Ahab's house through his maternal connection to Jezebel's bloodline.</p>",
        "29": "<p><b>v29 — The eleventh year of Joram son of Ahab, Ahaziah began to reign</b><br>A synchronistic note anchors Ahaziah's accession: the eleventh year of Joram son of Ahab over Israel. This synchronism conflicts with the accession notice in 2 Kings 8:25 (twelfth year) — a well-known textual crux usually resolved by counting conventions (inclusive/exclusive reckoning). The note functions to tie Ahaziah's fate to Joram's as part of one historical moment, not two separate careers.</p>",
        "30": "<p><b>v30 — Jezebel paints her eyes and adorns her head</b><br>When Jehu comes to Jezreel, Jezebel hears, paints her eyes with kohl (<i>va-tasem ba-pukh eineiha</i>), adorns her hair, and looks out through the window. The act has been interpreted variously: as seduction, as defiance, or as a queen choosing to meet death in full royal dignity rather than in terror. She is dying as a queen, not as a fugitive. Her verbal assault on Jehu from the window ('Is it peace, you Zimri, murderer of your master?') names him with the most shameful precedent — Zimri, who killed his king and lasted seven days (1 Kings 16:9-15).</p>",
        "31": "<p><b>v31 — Is it peace, Zimri, killer of your master?</b><br>Jezebel's taunt invokes Zimri — the short-lived assassin-king who lasted one week before Omri swept him away. The comparison is calculated: Zimri killed his master Elah and took the throne, only to be immediately overwhelmed. Jezebel is suggesting that Jehu's rebellion will be equally short-lived. It is also possibly a legal accusation — the word for 'killer of his master' (<i>horeg adonav</i>) frames Jehu as a criminal, not a legitimate king. She dies with this challenge on her lips.</p>",
        "32": "<p><b>v32 — Who is on my side? Throw her down</b><br>Jehu looks up at the window and calls: <i>'Mi iti mi'</i> — 'Who is with me? Who?' Two or three eunuchs (<i>sarisei</i>) look out at him. He commands: <i>'Shifluha'</i> — 'Throw her down.' The eunuchs' obedience is immediate. The palace servants are the instruments of her death — those within her own household turn against her. The eunuchs may have grievances of their own, or they may simply read the moment accurately.</p>",
        "33": "<p><b>v33 — They threw her down and her blood spattered</b><br>They throw her down; her blood spatters (<i>va-yiz</i>) on the wall and on the horses; and the horses trampled her (<i>va-yirmesuha</i>). The scene is deliberately un-sanitized: the violence is graphic and total. This is not burial or honor — it is obliteration. The horses trampling her body completes the dehumanizing end that the oracle had promised. The fulfillment of Elijah's word has arrived.</p>",
        "34": "<p><b>v34 — Go and bury this cursed woman</b><br>When Jehu goes in to eat and drink, he commands: 'See to this cursed woman (<i>ha-arurah ha-zot</i>) and bury her, for she is a king's daughter.' The phrase <i>bat melech</i> (daughter of a king) grants minimal acknowledgment of status — Jezebel was daughter of Ethbaal king of the Sidonians (1 Kings 16:31). Even in issuing a burial order, Jehu shows no grief or magnanimity; the concession to burial is merely a minimum owed to royal lineage.</p>",
        "35": "<p><b>v35 — They found no more of her than skull, feet, and palms of hands</b><br>When they go to bury her, they find only the skull (<i>gulgolet</i>), feet (<i>raglayim</i>), and palms of the hands (<i>kapot ha-yadayim</i>). The dogs have consumed the rest. The scene answers the oracle precisely: nothing left to bury. The word <i>gulgolet</i> (skull) will recur at Golgotha — the skull-place — but here it marks the literal fulfillment of a prophetic curse.</p>",
        "36": "<p><b>v36 — This is the word of the LORD that he spoke by Elijah</b><br>When they report to Jehu what was found, he declares: <i>'Zeh ha-davar asher diber YHWH be-yad Eliyahu ha-Tishbi'</i> — 'This is the word which the LORD spoke by the hand of Elijah the Tishbite.' Then he recites the oracle from 1 Kings 21:23 almost verbatim: 'In the plot of Jezreel the dogs shall devour Jezebel's flesh.' The explicit citation of Elijah's name and oracle is a narrator's signature — this entire sequence has been the fulfillment of a word spoken years before. The text wants the reader to register the correlation.</p>",
        "37": "<p><b>v37 — She shall be as dung on the face of the ground</b><br>The oracle continues: Jezebel's corpse shall be like dung (<i>ke-domen</i>) on the surface of the ground in the plot of Jezreel, so that none can say 'This is Jezebel.' The most feared aspect is erasure: no grave marker, no named resting place, no monument. In the ancient world where royal tombs were markers of ongoing dynasties, to die without burial is to be erased from memory. The oracle accomplishes theological and practical goals simultaneously — justice is visible, and the dynasty dies without a grave to rally around.</p>"
    },
    "10": {
        "1": "<p><b>v1 — Seventy sons of Ahab in Samaria</b><br>Jehu sends letters to the officials of Jezreel (<i>sarei Yizreel</i>), the elders (<i>zeqenim</i>), and the guardians (<i>omenei</i>) of Ahab's sons — seventy princes in Samaria. The number seventy is both precise and symbolic: a round generational number (cf. the 70 sons of Gideon in Judg 8:30; the 70 nations of Gen 10). These are not necessarily Ahab's biological sons alone but the broader royal household and extended noble class under Ahab's name. The letter-writing campaign (rather than direct military action) shows Jehu operating politically as well as militarily.</p>",
        "2": "<p><b>v2 — You have chariots, horses, a fortified city, and weapons</b><br>The letter challenges Samaria's leadership: you have your master's sons, chariots and horses, a fortified city (<i>ir ha-mivtzar</i>), and weapons. Jehu is acknowledging their capacity to resist and essentially calling their bluff. The implicit question: 'Will you fight for Ahab's house?' The opening gambit is to force them to declare their loyalty before Jehu's force arrives. This is military-psychological pressure: appear powerful enough to win, invite them to capitulate rather than fight.</p>",
        "3": "<p><b>v3 — Choose the best qualified of your master's sons and set him on his father's throne</b><br>Jehu's letter tells them to select the best (<i>ha-tov ve-ha-yashar</i> — the good and the right) of their master's sons, set him on his father's throne, and fight for your master's house. This is deliberate provocation: Jehu knows they cannot do this. Having just witnessed the death of Joram and Ahaziah, they know Jehu's military force is overwhelming. He is testing whether anyone will champion the Omride cause, knowing no one will.</p>",
        "4": "<p><b>v4 — The officials are terrified and say: Two kings could not withstand him</b><br>The officials of Samaria are very afraid (<i>vayir'u me'od me'od</i> — emphatic doubling). They reason among themselves: 'Behold, two kings could not stand before him — how shall we stand?' The reference is to Joram and Ahaziah, both already dead. The doubling of <i>me'od</i> emphasizes their paralysis. The question is rhetorical: they have already decided to surrender before formally responding.</p>",
        "5": "<p><b>v5 — We are your servants and will do whatever you tell us</b><br>The palace administrator (<i>asher al-habayit</i>), the city governor, the elders, and the guardians send back word: 'We are your servants (<i>avadecha</i>) and we will do everything you say. We will not make anyone king. Do whatever is good in your eyes.' The complete capitulation is expressed in four concise statements. The transition of power is accomplished by letter without a battle — Jehu has taken Samaria politically before arriving militarily.</p>",
        "6": "<p><b>v6 — Bring the heads of the men of your master's sons to me at Jezreel</b><br>Jehu writes again: 'If you are on my side and will listen to my voice, take the heads of your master's sons (<i>rashei anshei benei adoneichem</i>) and come to me in Jezreel at this time tomorrow.' The Hebrew <i>rashei</i> can mean 'heads' literally or 'leading men' — but Jehu's intent is quickly revealed. The seventy sons of Ahab were with the great men of the city who were raising them — the guardians and the city elite. What follows makes clear that 'heads' means heads.</p>",
        "7": "<p><b>v7 — Seventy heads placed in baskets and sent to Jezreel</b><br>When the letter arrives, the city leaders take the king's sons — seventy men — and slaughter them (<i>va-yishchatu</i>). They put their heads in baskets (<i>ba-dudim</i>) and send them to Jehu in Jezreel. The image is deliberately horrifying: seventy heads in baskets, delivered like a commercial shipment. The guardians of the princes have become their executioners, doing for political survival what Jehu could not have done alone without storming Samaria.</p>",
        "8": "<p><b>v8 — Make two heaps at the city gate until morning</b><br>A messenger comes to tell Jehu: 'They have brought the heads of the king's sons.' Jehu says, 'Put them in two heaps at the entrance of the gate (<i>shenei tzovarot</i>) until morning.' The public display of severed heads at the city gate serves as visual proclamation of the new order. Morning will bring the official public reckoning. The gate was the social center of the ancient city — the place of commerce, judgment, and assembly. The heaps are placed where all will see.</p>",
        "9": "<p><b>v9 — You are righteous; I conspired against my master — but who struck all these?</b><br>In the morning Jehu stands and speaks to the assembled people: <i>'Tzadiqim atem'</i> — 'You are righteous.' He acknowledges that he conspired against (<i>qashtarti</i>) and killed his master Joram. But then: 'Who struck all these?' The rhetorical question deflects. Jehu is saying: I killed Joram, that was my doing — but the 70 princes of Samaria? That was not my hand. Implicitly: it was divine providence working through others. He is positioning himself as God's instrument, not an ambitious killer.</p>",
        "10": "<p><b>v10 — Know that not a word of the LORD will fall to the ground</b><br><i>'De'u epho ki lo yipol mi-davar YHWH artzah'</i> — 'Know then that not a word of the LORD will fall to the ground.' The specific prophecy fulfilled was Elijah's against the house of Ahab (1 Kings 21:21-22). Jehu explicitly interprets the events theologically: the mass death of Ahab's house is not political accident or military coup but prophetic fulfillment. The phrase <i>lo yipol artzah</i> (will not fall to the ground) is a technical idiom for prophetic reliability — a word given by God does not miss its target.</p>",
        "11": "<p><b>v11 — Jehu strikes all who remain of Ahab's house in Jezreel</b><br>Jehu kills all who remain of the house of Ahab in Jezreel — all his great men (<i>gedolav</i>), his close friends (<i>me'udav</i>), and his priests (<i>kohanav</i>) — until he leaves no survivor to Ahab. The scope of the purge extends beyond the royal family proper to the entire support network: the aristocratic clients, the personal confidants, and the cult personnel attached to Ahab's regime. A new king removing the religious and social structure of the old dynasty is standard ANE practice.</p>",
        "12": "<p><b>v12 — On the way to Samaria at Beth-Eked of the Shepherds</b><br>Jehu sets out for Samaria. En route he comes to Beth-Eked of the Shepherds (<i>Beit Eqed ha-ro'im</i>) — probably a sheepshearing station or gathering place, a liminal roadside location. Here he encounters the brothers of Ahaziah king of Judah coming down to greet the sons of the king and the sons of the queen mother (<i>gelulei ha-melech u-venei ha-gevirah</i>).</p>",
        "13": "<p><b>v13 — Brothers of Ahaziah on their way to greet the king's family</b><br>Forty-two men, relatives of Ahaziah, announce they are going down to greet (<i>lishalom</i> — the same root as shalom, peace) the sons of the king and the sons of the queen mother. They do not yet know Ahaziah is dead. Their errand of cordial greeting walks them into a trap. The word <i>shalom</i> continues its dark irony throughout this chapter — they seek peace and find execution.</p>",
        "14": "<p><b>v14 — Seize them alive — forty-two men killed at Beth-Eked</b><br>Jehu commands: 'Seize them alive' (<i>tifsum chayyim</i>). They are seized alive and slaughtered (<i>va-yishchatem</i>) at the pit of Beth-Eked — forty-two men. Jehu left not one of them alive. The connection to Ahaziah (who had been killed at Megiddo) and his Judean relatives makes this an extension of the anti-Omride purge: Ahaziah's mother Athaliah was a daughter of Ahab (or Omri), so these Judean royal relatives were also Omride kin.</p>",
        "15": "<p><b>v15 — Jehonadab son of Rechab: 'Is your heart right as my heart is with yours?'</b><br>Jehu meets Jehonadab son of Rechab (<i>Yehonadav ben Rekhav</i>), who is coming to meet him. Jehonadab is the founder of the Rechabite movement — an ascetic group that refused wine, houses, and agriculture (Jer 35). Their ideology was Yahwistic puritanism: live as in the wilderness, refuse the corruptions of Canaanite settled life. Jehu greets him: 'Is your heart right (<i>yashar</i>) with my heart as mine is with yours?' Jehonadab answers, 'It is.' Jehu: 'If so, give me your hand' (<i>tena et-yadecha</i>). He takes him up into the chariot.</p>",
        "16": "<p><b>v16 — Come with me and see my zeal for the LORD</b><br>'Come with me and see my zeal for the LORD' (<i>lecha iti ur'eh be-qin'ati la-YHWH</i>). The word <i>qin'ah</i> (zeal/jealousy) is used of God's own passion for exclusive worship (Exod 20:5: 'I am a jealous God') and of Phinehas (Num 25:11 — Phinehas was zealous with my zeal). Jehu claims the mantle of zealous Yahwism — purging Baal worship with the same intensity as the covenant demands. Whether this zeal was genuine religious conviction or political rhetoric the narrator does not resolve directly.</p>",
        "17": "<p><b>v17 — Jehu kills all who remained to Ahab in Samaria</b><br>When Jehu comes to Samaria, he strikes down all who remained to Ahab there — finishing the work. The phrase <i>ad-hashmeido ke-davar YHWH asher diber el-Eliyahu</i> — 'until he had annihilated them, according to the word of the LORD that he spoke to Elijah' — is the narrator's direct statement of purpose. The killing is framed not as political purge but as fulfillment of prophecy. This refrain ties the chapter together with vv10 and 36.</p>",
        "18": "<p><b>v18 — Ahab served Baal a little; Jehu will serve him much</b><br>Jehu calls all the people together and announces: 'Ahab served Baal a little (<i>me'at</i>), but Jehu will serve him much (<i>harbeh</i>).' This is deliberate deception — an elaborate ruse. The irony is sharp: Jehu, who just purged Baal's supporters, now announces he will outdo Ahab in Baal worship. The trap is baited for Baal's surviving adherents to reveal themselves.</p>",
        "19": "<p><b>v19 — Summon all the prophets of Baal and all his worshipers</b><br>Jehu commands a great sacrifice to Baal and summons all Baal's prophets, servants, and priests — none must be absent, for the sacrifice is great. Whoever is absent shall not live. The threat ensures maximum attendance. The narrator adds the parenthetical: 'But Jehu did it with cunning (<i>be-aqbah</i>) in order to destroy the worshipers of Baal.' The word <i>aqbah</i> (cunning/guile) acknowledges the deception without condemning it — the narrator presents it as a legitimate counter to Baal's hold on Israel.</p>",
        "20": "<p><b>v20 — Proclaim a solemn assembly for Baal</b><br>Jehu declares an <i>atzarah</i> (solemn assembly/convocation) for Baal. The term <i>atzarah</i> is normally used for Israelite assembly before YHWH (Lev 23:36; Deut 16:8; Amos 5:21) — its use here for a Baal gathering is ironic and deliberate. The form of a sacred assembly is being used to eliminate a false god's followers. The Baal worshipers are gathering to worship; they are actually gathering to be killed.</p>",
        "21": "<p><b>v21 — The house of Baal was filled from end to end</b><br>Jehu sends throughout all Israel, and all the servants of Baal come — not one is absent. They go into the house of Baal, and the house of Baal is filled from one end to the other (<i>va-yimmale beit-ha-Ba'al pe le-feh</i>). The phrase <i>pe le-feh</i> (mouth to mouth / from end to end) signals total occupancy. The stage is set: all of Baal's worshipers in Israel are in one building. Jehu and Jehonadab then enter the temple.</p>",
        "22": "<p><b>v22 — Bring out the vestments for all the servants of Baal</b><br>Jehu instructs the keeper of the wardrobe (<i>asher al-ha-malbusha</i>) to bring out garments (<i>levushim</i>) for all the servants of Baal. They are dressed in cultic vestments — the formal robes of Baal worship. This may have been standard practice for Baal sacrifice (priests and worshipers wearing designated garments), or it may serve a practical purpose: distinguishing Baal worshipers from any Yahweh worshipers who might be present, or simply identifying them for what follows.</p>",
        "23": "<p><b>v23 — Jehonadab and Jehu examine the assembly for any servants of YHWH</b><br>Jehu and Jehonadab enter the house of Baal and say to the Baal worshipers: 'Search and see (<i>chapshu ur'u</i>) that there is here with you no servant of the LORD — only servants of Baal.' The presence of Jehonadab (the Rechabite purist) at this moment gives the scene theological legitimacy: the most rigorous Yahwist in Israel is co-signer of the operation. The check for YHWH-worshipers in the crowd protects innocents before the slaughter begins.</p>",
        "24": "<p><b>v24 — Eighty men stationed outside</b><br>When they went in to make offerings and burnt offerings, Jehu stationed eighty men outside and said: 'The man who allows any of the men I am putting into your hand to escape — his life shall be for the life of another.' The eighty soldiers form a perimeter preventing escape. The threat against them — their lives for any escapee — ensures their vigilance. The trap is set: worshipers inside, soldiers outside, no exit.</p>",
        "25": "<p><b>v25 — As soon as he had finished the burnt offering, strike them</b><br>As soon as Jehu finished offering the burnt offering (<i>kekhaloto la'asot ha-olah</i>), he commanded the guards and officers: 'Go in and strike them down (<i>he-viu haruguhu</i>); let none come out.' They strike with the sword. The guards and officers throw them out and go to the inner room of the house of Baal. The moment of transition from sacred gesture to military massacre is stark: the cult act is the ruse that holds the crowd in place until the order comes.</p>",
        "26": "<p><b>v26 — The pillar of the house of Baal is brought out and burned</b><br>They bring out the <i>matzevot</i> (pillars/standing stones) of the house of Baal and burn them (<i>va-yisrefu</i>). The pillars (<i>matzevot</i>) are the sacred standing stones associated with Baal worship — erected at high places and cult centers throughout Canaan. Burning them goes beyond mere destruction to desecration, ensuring they cannot be re-used for worship.</p>",
        "27": "<p><b>v27 — The pillar of Baal demolished; the house of Baal made a latrine</b><br>They demolish the pillar of Baal (<i>va-yitstzu et-matzevat ha-Ba'al</i>) and demolish the house of Baal itself, making it a latrine (<i>machra'ot</i> — a privy/dung pit) to this day. The desecration is total and deliberately humiliating: the most sacred Baal site in Israel is converted into a public toilet. The phrase 'to this day' (<i>ad ha-yom ha-zeh</i>) is a narrator's note confirming the site's continuing degraded status in the writer's own time.</p>",
        "28": "<p><b>v28 — Jehu wiped out Baal from Israel</b><br><i>'Va-yashmed Yehu et-ha-Ba'al mi-Yisrael'</i> — 'Jehu wiped out Baal from Israel.' This is the summary verdict, stated simply and completely. The verb <i>shamad</i> (to destroy/exterminate) is the same used for total destruction of enemies. Whatever Jehu's theological motivations, the institutional reality is that the Baal-worship apparatus that Jezebel had established in Israel — its temples, its priesthood, its royal patronage — was dismantled in these events.</p>",
        "29": "<p><b>v29 — But the sins of Jeroboam the son of Nebat Jehu did not depart from</b><br>The qualification follows immediately: <i>'Raq chatot Yarov'am ben-Nevat asher hecheti et-Yisrael lo-sar Yehu me-achareihem'</i> — 'However, from the sins of Jeroboam son of Nebat, who made Israel sin, Jehu did not turn aside.' The golden calves at Bethel and Dan, established by the first northern king as state-sponsored non-Jerusalem worship, remained. Jehu purged Baal but kept Jeroboam's sin intact. The Deuteronomist's assessment: partial reform, insufficient obedience. The Northern Kingdom's structural apostasy — alternative sanctuaries to Jerusalem — persisted.</p>",
        "30": "<p><b>v30 — Because you have done well, your sons to the fourth generation shall sit on the throne</b><br>The LORD speaks to Jehu: <i>'Ya'an asher hetavta la'asot ha-yashar be-einai'</i> — 'Because you have done well in carrying out what is right in my eyes.' For this, Jehu's sons shall sit on the throne of Israel to the fourth generation. The promise is calibrated: not 'forever' as with David (2 Sam 7), but four generations. Jehu's dynasty (Jehoahaz, Joash, Jeroboam II, Zechariah) did indeed last four generations before being cut off at Zechariah's assassination (2 Kings 15:12). The limitation is built into the promise itself.</p>",
        "31": "<p><b>v31 — But Jehu was not careful to walk in the law of the LORD with all his heart</b><br>The negative qualification of Jehu's reign: <i>'Ve-Yehu lo shomar lalekheth be-torat YHWH Elohei Yisrael be-chol-libbo'</i> — 'But Jehu was not careful to walk in the law of the LORD the God of Israel with all his heart.' The criterion is <i>kol-levavo</i> (all his heart) — the Deuteronomic standard of whole-hearted covenant loyalty. Jehu's anti-Baal purge was real, but his retention of Jeroboam's calves shows his Yahwism was political and partial, not the total covenant fidelity the law requires.</p>",
        "32": "<p><b>v32 — The LORD began to cut off parts of Israel; Hazael defeated Israel on all the borders</b><br>In those days the LORD began to cut off (<i>va-yachel YHWH liqatztzot be-Yisrael</i>) territory from Israel. Hazael of Aram struck Israel throughout the territory — from the Jordan eastward, all Gilead, Gad, Reuben, Manasseh — from Aroer by the Arnon to Gilead and Bashan. The Aramaean pressure that had been building since Elijah's day now begins to take concrete territorial form. Israel's covenant failure (Jeroboam's calves) translates into covenant curse (loss of land).</p>",
        "33": "<p><b>v33 — All the land of Gilead lost to Aram</b><br>The territory lost is described in detail: from Aroer (<i>me-Aro'er</i>) by the Arnon River, including Gilead and Bashan — the Transjordanian territories. These were lands seized under Moses and Joshua (Num 32; Josh 13) and held as part of the promise. Their loss is not random but covenantal: the land was given in faithfulness; it is taken back through judgment. Hazael becomes the instrument of YHWH's discipline exactly as foreign powers function throughout the Deuteronomic history.</p>",
        "34": "<p><b>v34 — The rest of Jehu's acts and his might</b><br>The regnal formula closes Jehu's reign: 'Now the rest of the acts of Jehu and all that he did, and all his might, are they not written in the Book of the Chronicles of the Kings of Israel?' The <i>sefer divrei ha-yamim le-malkhei Yisrael</i> (the Book of the Chronicles of the Kings of Israel) is the lost source document the author of Kings cites repeatedly — a palace record or court annals no longer extant. Jehu's reign lasted 28 years (v36), longer than any other northern king except Jeroboam II.</p>",
        "35": "<p><b>v35 — Jehu slept with his fathers and was buried in Samaria</b><br>Jehu died and was buried in Samaria, the northern capital he had purged and now governed. Unlike the kings of Judah whose burial in 'the city of David' (Jerusalem) signals dynastic legitimacy, northern kings are buried in their capitals without the same Davidic framing. The burial in Samaria is matter-of-fact: he was king, he died, he was buried where kings are buried.</p>",
        "36": "<p><b>v36 — Jehu reigned twenty-eight years over Israel in Samaria</b><br>Jehu's reign lasted <i>esrim ve-shmoneh shanah</i> (twenty-eight years). The synchronism: he began in the 28th year of Jehoshaphat's line (per 9:29 — the 12th year of Joram of Israel; Ahaziah of Judah began in year 11 or 12). Jehu's reign (841–814 BCE by standard chronology) corresponds to the period of Aramaean dominance; the Assyrian king Shalmaneser III's Black Obelisk even depicts a figure labeled 'Iaua son of Humri' (Jehu son of Omri — Assyrian designation for the kingdom) paying tribute, dated 841 BCE.</p>",
    },
    "11": {
        "1": "<p><b>v1 — Athaliah destroys all the royal offspring</b><br>When Athaliah the mother of Ahaziah (<i>em Achazyahu</i>) saw that her son was dead, she arose and destroyed (<i>va-taved</i>) all the royal offspring (<i>et kol-zera ha-mamlakhah</i>). Athaliah, daughter of Ahab and Jezebel (or Omri — the texts vary), was the Phoenician-Baal-influenced queen mother who seizes power at Ahaziah's death. The word <i>taved</i> (she destroyed/she arose to destroy) is emphatic and total — she attempts to liquidate the entire Davidic line in one act. The motive is power; the method is massacre.</p>",
        "2": "<p><b>v2 — Jehosheba hides Joash in the bedchamber</b><br>Jehosheba (<i>Yehosheva</i>), daughter of King Joram and sister of Ahaziah (thus Athaliah's step-daughter), takes Joash (<i>Yoash</i>) son of Ahaziah and steals him away from among the king's sons who are being slain. She puts him and his nurse in the bedchamber (<i>cheder ha-mittot</i> — lit. the room of beds/mattresses). They hide him from Athaliah so he is not killed. Jehosheba's act is the pivot on which the entire Davidic promise hangs: one child hidden in a storage room keeps the line alive.</p>",
        "3": "<p><b>v3 — Six years hidden in the house of the LORD</b><br>He was with her, hidden in the house of the LORD (<i>chuva itto beit YHWH</i>) for six years, while Athaliah reigned over the land. The temple becomes the sanctuary — literally, the sacred space where the heir is preserved while a usurper rules. The temple personnel (priests and Levites) become the custodians of Davidic continuity. Six years is a long time for a secret to hold; the narrative implies that the temple staff's discretion and loyalty protected the child.</p>",
        "4": "<p><b>v4 — Jehoiada summons the commanders and makes a covenant in the temple</b><br>In the seventh year (<i>ba-shanah ha-shevi'it</i>), Jehoiada the priest (<i>ha-kohen</i>) sends and summons the captains of the hundreds (<i>sarei ha-me'ot</i>) — both Carites (<i>ha-Kari</i>) and guards (<i>ha-ratzim</i>) — and brings them into the house of the LORD. He makes a covenant with them and administers an oath, showing them the king's son. The six-year wait is over; the priest-organized military coup begins in the temple itself, not the palace. The sacred space is the operational center of regime change.</p>",
        "5": "<p><b>v5 — A third of you shall guard the king's house on the sabbath</b><br>Jehoiada instructs the commanders: a third of those coming on duty on the sabbath shall guard the royal palace, a third the gate of Sur, a third the gate behind the guards. This coordinates temple guards and palace guards into a unified security operation around the sabbath shift change — a moment when personnel movements would be expected and less suspicious. The sabbath rotation provided natural cover for an unusually large gathering of armed men.</p>",
        "6": "<p><b>v6 — The gate of Sur and the guard gate</b><br>A third shall be at the gate of Sur and a third at the gate behind the guards. They are to guard the house (<i>mishmar ha-bayit</i>) so it is not broken through (<i>min-hapharetz</i>). The geography of the gates is partially unclear — 'the gate of Sur' does not appear elsewhere, and exact locations are uncertain. The tactical goal is perimeter control: all major entry points to the palace-temple complex are covered by loyal forces before the public coronation.</p>",
        "7": "<p><b>v7 — The two divisions off duty shall guard the king</b><br>The two groups coming off sabbath duty are to guard the house of the LORD around the king. Jehoiada is staging the coronation with military precision: on-duty guards hold the perimeter; off-duty guards form the king's honor guard. The result is a complete military cordon around the young king from before the moment of public disclosure.</p>",
        "8": "<p><b>v8 — Anyone who approaches the ranks shall be killed</b><br>The standing order: <i>'Ve-ha-ba el-ha-sederot yumat'</i> — 'Whoever approaches within the ranks shall be put to death.' Anyone who tries to interfere with the formation is to be killed on the spot. The guards are to accompany the king wherever he goes. The phrase emphasizes that this is now a military operation, not a religious ceremony — the king's safety requires lethal force authorization.</p>",
        "9": "<p><b>v9 — The commanders do as Jehoiada commanded</b><br>The commanders of the hundreds do everything as Jehoiada the priest commanded. They take their men — those coming on duty on the sabbath and those going off duty — and come to Jehoiada the priest. The obedience is total and rapid: Jehoiada commands; the military follows. The priest's authority in this moment exceeds the palace's authority, because the temple holds the legitimate king.</p>",
        "10": "<p><b>v10 — Jehoiada gives the commanders the spears and shields of King David</b><br>The priest gives the commanders the spears and shields (<i>ha-chanit ve-ha-maginot</i>) that had belonged to King David, which were in the house of the LORD. The weapons of David stored in the temple carry symbolic weight: they connect this coronation to the original Davidic monarchy. Arming the coup with David's own weapons is a statement that what is happening is Davidic restoration, not a new political venture.</p>",
        "11": "<p><b>v11 — Guards standing with weapons from south to north corner of the altar</b><br>The guards stand each with his weapons in hand — from the south side of the house to the north side, before the altar and the house — surrounding the king on all sides. The formation is described in terms of the temple's liturgical geography: the altar as the center point, guards forming a ring from one end to the other. The sacred space becomes a parade ground; the coronation will happen within the cultic precinct itself.</p>",
        "12": "<p><b>v12 — The nezer and the edut: 'Long live the king!'</b><br>Jehoiada brings out the king's son and places on him the <i>nezer</i> (crown/diadem) and the <i>edut</i> (testimony/covenant document). The <i>nezer</i> is the royal crown or diadem — also used of the high priest's golden plate (Exod 29:6). The <i>edut</i> is more debated: it may be the covenant document the king was supposed to hold (Deut 17:18-19 — the king was to write a copy of the Torah), or a specific treaty or accession document. Then they clap hands (<i>va-yikefu kapayim</i>) and shout <i>'Yechi ha-melech'</i> — 'Long live the king!'</p>",
        "13": "<p><b>v13 — Athaliah hears the noise of the guard and the people and goes to the temple</b><br>Athaliah hears the noise of the people (<i>qol ha-am ha-rats</i> — the sound of the running people) and comes into the house of the LORD to the people. She had been in the palace, presumably unaware until the shout and commotion penetrated the walls. Her coming to the temple is the trap closing: she walks toward the sound without yet knowing what has happened.</p>",
        "14": "<p><b>v14 — Athaliah sees the king standing by the pillar</b><br>She looks and sees the king standing by the pillar (<i>al-ha-ammud</i>) as was the custom — the royal station at the temple entrance (cf. 2 Kings 23:3). The commanders and trumpeters are beside the king; all the people of the land are rejoicing (<i>same'ach</i>) and blowing trumpets. Athaliah tears her clothes and cries: <i>'Qesher qesher'</i> — 'Treason! Treason!' The word <i>qesher</i> (conspiracy/treason) is ironic: she calls legitimate Davidic restoration treason.</p>",
        "15": "<p><b>v15 — Take her outside the ranks and kill anyone who follows her</b><br>Jehoiada commands the officers: 'Bring her out between the ranks (<i>bein ha-sederot</i>), and put to the sword anyone who follows her.' His instruction: 'Do not put her to death in the house of the LORD.' The temple must not be defiled by blood — even the blood of a tyrant. Athaliah is led out through the horses' entrance of the palace and killed there. The killing happens outside sacred space, preserving the temple's purity while accomplishing the political necessity.</p>",
        "16": "<p><b>v16 — She is killed at the king's palace</b><br>Athaliah is led out by force through the horses' gate (<i>sha'ar ha-susim</i> — the entrance to the stables and palace grounds) and put to death there. The location — a utilitarian, non-sacred space — contrasts with the royal and sacred character of the coronation just completed. The usurper dies at the horses' gate; the king stands at the pillar of the temple. The spatial contrast reinforces the legitimacy contrast.</p>",
        "17": "<p><b>v17 — Jehoiada makes the covenant between LORD, king, and people</b><br>Jehoiada makes the covenant (<i>va-yikrot ha-berit</i>) — between the LORD and the king and the people, that they should be the LORD's people — and between the king and the people. This three-party covenant (God / king / people) is the constitutional foundation of the restored Davidic monarchy. The structure mirrors Mosaic covenant theology: YHWH as sovereign, king as covenant administrator, people as covenant recipients. The ceremony re-establishes what Athaliah's Baal-influenced reign had disrupted.</p>",
        "18": "<p><b>v18 — All the people go to the house of Baal and tear it down</b><br>All the people of the land go to the house of Baal and tear it down (<i>va-yitsetzu</i>). His altars and images are smashed completely (<i>shibber shibber</i> — emphatic reduplication: they utterly smash), and Mattan the priest of Baal is killed before the altars. The pattern mirrors Jehu's purge in the north: covenant renewal immediately followed by anti-Baal action. The Baal temple in Jerusalem — apparently established under Athaliah who imported her parents' religion — is now destroyed.</p>",
        "19": "<p><b>v19 — The king is brought from the temple to the palace through the gate of the guards</b><br>Jehoiada takes the captains, the Carites, the guards, and all the people of the land, and they escort the king from the house of the LORD through the gate of the guards (<i>sha'ar ha-ratzim</i>) to the king's house. The processional route — from temple to palace through the guard gate — is the inverse of Athaliah's exit through the horse gate. The legitimate king moves from the sacred space that sheltered him to the royal seat that is now his by right.</p>",
        "20": "<p><b>v20 — All the people of the land rejoiced, and the city was quiet</b><br><i>'Va-yismach kol-am ha-aretz ve-ha-ir shaqatah'</i> — 'All the people of the land rejoiced, and the city was quiet.' The contrast with v13 (when Athaliah heard the noise — <i>qol</i>) is deliberate: what was tumult becomes peace; what was an alarm becomes jubilation. <i>Ha-ir shaqatah</i> (the city was quiet) uses the same root as <i>shalom</i> — the city now has the peace it could not have under Athaliah's illegitimate and foreign-religious reign.</p>",
        "21": "<p><b>v21 — Joash was seven years old when he began to reign</b><br><i>'Ben-sheva shanim Yehoash be-molkho'</i> — 'Joash was seven years old when he began to reign.' The youngest king in the narrative of Kings begins a 40-year reign (2 Kings 12:1). His youth and the circumstances of his preservation — hidden by a princess, sheltered in the temple, crowned by a priest — are unique in the history of the monarchy. The Chronicler's parallel account (2 Chr 24) develops the story of his reign at greater length, including the sad decline after Jehoiada's death. For now, at seven years old, the Davidic line has survived.</p>"
    }
}

def main():
    existing = load_comm('mkt-original', '2kings')
    merge_comm(existing, TWO_KINGS_ORIGINAL)
    save_comm('mkt-original', '2kings', existing)
    # verify coverage
    for ch in ['9', '10', '11']:
        filled = set(existing.get(ch, {}).keys())
        print(f'  ch{ch}: {len(filled)} verses — {sorted(filled, key=int)[:4]}...')
    print('2 Kings original fill (chs 9–11) done.')

if __name__ == '__main__':
    main()
